def Trow(n: int) -> list[int]:
    if n == 0: return [1]
    row = [0] * (n + 1)
    fact = 1
    for k in range(1, n + 1):
        if k > 1: fact *= (k - 1)
        total = 0; binom = 1
        for j in range(k):
            term = binom * pow(n + k - 1 - j, n + k - 1)
            total += term if j % 2 == 0 else -term
            binom = binom * (k - 1 - j) // (j + 1)
        sk = total // fact
        coeff = 1
        for t in range(k, n + 1):
            row[t] += coeff * sk
            shift = t - k + 1
            if t < n:
                coeff = -coeff * (2 * (n + 1) - shift) // shift
    return row
